import "@pagewright/blocks/blocks.css";
import { parseSiteConfig } from "@pagewright/blocks";
import { createThemeInitScript } from "@pagewright/site-kit";
import siteDoc from "../data/site.json";

interface Props {
  title?: string;
  description?: string;
}

const { title, description } = Astro.props;
const siteConfig = parseSiteConfig(siteDoc);
const pageTitle = title ? `${title} · ${siteConfig.name}` : siteConfig.name;
const pageDescription = description ?? siteConfig.description ?? "";
const themeInitScript = createThemeInitScript(siteConfig.defaultTheme);
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <meta name="generator" content="Pagewright" />
    <title>{pageTitle}</title>
    {pageDescription && <meta name="description" content={pageDescription} />}
    <script is:inline set:html={themeInitScript} />
  </head>
  <body class="pw-root">
    <slot />
  </body>
</html>

---
import Layout from "../layouts/Layout.astro";
import {
  PageRenderer,
  createSiteBindings,
  parsePage,
  parseSiteConfig,
  resolveBindings,
} from "@pagewright/blocks";
import homeDoc from "../data/pages/home.json";
import siteDoc from "../data/site.json";

// Validate + apply schema defaults at build time so malformed content fails loudly.
const page = parsePage(homeDoc);
const site = parseSiteConfig(siteDoc);
const resolvedPage = resolveBindings(page, createSiteBindings(site));
const base = import.meta.env.BASE_URL;
---

<Layout title={resolvedPage.title} description={resolvedPage.description}>
  <PageRenderer blocks={page.blocks} base={base} site={site} />
</Layout>

