import { parseSiteConfig } from "@pagewright/blocks";
import { createThemeInitScript } from "@pagewright/site-kit";
import siteDoc from "../data/site.json";

interface Props {
  title?: string;
  description?: string;
}

const { title, description } = Astro.props;
const siteConfig = parseSiteConfig(siteDoc);
const pageTitle = title ? `${title} · ${siteConfig.name}` : siteConfig.name;
const pageDescription = description ?? siteConfig.description ?? "";
const themeInitScript = createThemeInitScript(siteConfig.defaultTheme);
