import Layout from "../../layouts/Layout.astro";
import {
  PageRenderer,
  PostHeader,
  createSiteBindings,
  parseSiteConfig,
  resolveBindings,
} from "@pagewright/blocks";
import { getPublishedPosts, type LoadedPost } from "../../lib/posts";
import siteDoc from "../../data/site.json";

