}

/**
 * Base-path awareness for generated sites.
 *
 * GitHub Pages *project* sites are served from `/<repo>/`, so a root-relative asset like an uploaded
 * image (`/media/logo.png`) or an internal link (`/blog/hello/`) would 404 unless it is prefixed with
 * the site's base path. Astro exposes that value as `import.meta.env.BASE_URL` (always `/`-terminated,
 * e.g. `/my-repo/` or `/`), which the templates thread into {@link PageRenderer} via the `base` prop.
 * The Next.js builder preview renders from the app origin, so it simply uses the default base of `/`.
 *
 * These are plain functions (no React context) so the block components stay renderable as React
 * Server Components in the Next.js app and as static islands in Astro — `base` is threaded as an
 * explicit prop rather than through context, which RSC does not support.
 */

/** Extra prop carried by every block component so it can resolve root-relative URLs. */
export interface BaseAware {
  /** Site base path (e.g. `/my-repo/`). Defaults to `/`. */
  base?: string;
}

/** Normalize any incoming base to a leading+trailing-slashed path (or `/`). */
export function normalizeBase(base?: string | null): string {
  if (!base) return "/";
  let b = base.trim();
  if (b === "" || b === "/") return "/";
  if (!b.startsWith("/")) b = `/${b}`;
  if (!b.endsWith("/")) b = `${b}/`;
  return b;
}

/**
 * Prefix a root-relative internal URL with the site base path. Absolute URLs (`http(s)://`),
 * protocol-relative (`//cdn`), anchors (`#`), scheme URLs (`mailto:`, `tel:`, `data:`), and already
 * relative paths are returned untouched so they never get double-prefixed.
 */
export function withBase(base: string | undefined, url?: string): string | undefined {
  if (!url) return url;
  // Only root-relative internal paths get rewritten.
  if (!url.startsWith("/")) return url;
  if (url.startsWith("//")) return url;
  const b = normalizeBase(base);
  if (b === "/") return url;
  return `${b.replace(/\/$/, "")}${url}`;
}

import type { SiteConfig } from "./schema";

export const siteBindingDefinitions = [
  {
    key: "currentYear",
    token: "{{currentYear}}",
    label: "Current year",
    description: "The year when the site is built.",
  },
  {
    key: "site.name",
    token: "{{site.name}}",
    label: "Site name",
    description: "The name from global site settings.",
  },
  {
    key: "site.description",
    token: "{{site.description}}",
    label: "Site description",
    description: "The description from global site settings.",
  },
  {
    key: "site.url",
    token: "{{site.url}}",
    label: "Site URL",
    description: "The canonical URL from global site settings.",
  },
] as const;

export type SiteBindingKey = (typeof siteBindingDefinitions)[number]["key"];
export type BindingValues = Partial<Record<SiteBindingKey, string>> & Record<string, string>;

/** Build the common values available to authored `{{binding}}` tokens. */
export function createSiteBindings(
  site?: SiteConfig | null,
  now: Date = new Date(),
): BindingValues {
  const bindings: BindingValues = {
    currentYear: String(now.getUTCFullYear()),
  };
  if (site) {
    bindings["site.name"] = site.name;
    bindings["site.description"] = site.description ?? "";
    bindings["site.url"] = site.url ?? "";
  }
  return bindings;
}

/** Replace known `{{binding}}` tokens while preserving unknown tokens for forward compatibility. */
export function resolveBindingString(value: string, bindings: BindingValues): string {
  return value.replace(/\{\{\s*([A-Za-z0-9_.-]+)\s*\}\}/g, (token, key: string) => {
    const binding = bindings[key];
    return Object.prototype.hasOwnProperty.call(bindings, key) && binding !== undefined
      ? binding
      : token;
  });
}

/** Resolve tokens inside authored HTML without letting plain-text site details inject markup. */
export function resolveHtmlBindingString(value: string, bindings: BindingValues): string {
  const escapedBindings = Object.fromEntries(
    Object.entries(bindings).map(([key, binding]) => [
      key,
      binding
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#39;"),
    ]),
  ) as BindingValues;
  return resolveBindingString(value, escapedBindings);
}

/**
 * Resolve bindings recursively in JSON-shaped content such as block props, pages, and site links.
 * Non-string primitives are returned unchanged.
 */
export function resolveBindings<T>(value: T, bindings: BindingValues): T {
  if (typeof value === "string") {
    return resolveBindingString(value, bindings) as T;
  }
  if (Array.isArray(value)) {
    return value.map((item) => resolveBindings(item, bindings)) as T;
  }
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value).map(([key, item]) => [key, resolveBindings(item, bindings)]),
    ) as T;
  }
  return value;
}

import * as React from "react";
import type {
  BlockProps,
  BlockType,
  Link,
  SiteConfig,
} from "../schema";
import { BlockIcon } from "../icons";
import { withBase, normalizeBase, type BaseAware } from "../base";
import { getGitHubDiscussionsConfigIssues } from "../post-components";

/**
 * Block components. Plain React + scoped `pw-` CSS classes (see styles/blocks.css) so they render
 * pixel-identically in the Next.js builder preview and in generated Astro sites (via @astrojs/react).
 * No Tailwind dependency here on purpose — that keeps the two consumers perfectly in sync.
 *
 * Each block accepts an optional `base` (the site base path) threaded down from PageRenderer so that
 * root-relative image/link URLs resolve on GitHub Pages project sites.
 */

interface SiteAware {
  site?: SiteConfig;
}

function linkAttributes(link: Link, base?: string) {
  const href = withBase(base, link.href);
  const external = /^(?:https?:)?\/\//i.test(link.href);
  return {
    href,
    target: external ? "_blank" : undefined,
    rel: external ? "noopener noreferrer" : undefined,
  };
}

function LinkContent({ link }: { link: Link }) {
  return (
    <>
      {link.icon ? (
        <span className="pw-linkicon" aria-hidden="true">
          <BlockIcon name={link.icon} size={16} />
        </span>
      ) : null}
      <span>{link.label}</span>
    </>
  );
}

function linkDestinationKey(link: Link): string {
  const href = link.href.trim();
  try {
    return new URL(href).href;
  } catch {
    return href;
  }
}

function CtaLink({
  link,
  variant,
  base,
}: {
  link?: Link;
  variant: "primary" | "secondary";
  base?: string;
}) {
  if (!link) return null;
  return (
    <a className={`pw-btn pw-btn--${variant}`} {...linkAttributes(link, base)}>
      <LinkContent link={link} />
    </a>
  );
}

export function Navbar({ brand, logo, links = [], cta, base }: BlockProps<"navbar"> & BaseAware) {
  return (
    <nav className="pw-navbar">
      <div className="pw-container pw-navbar__inner">
        <a className="pw-navbar__brand" href={withBase(base, "/")}>
          {logo ? <img className="pw-navbar__logo" src={withBase(base, logo)} alt={brand} /> : null}
          <span>{brand}</span>
        </a>
        <div className="pw-navbar__links">
          {links.map((l, i) => (
            <a key={i} className="pw-navbar__link" {...linkAttributes(l, base)}>
              <LinkContent link={l} />
            </a>
          ))}
          <CtaLink link={cta} variant="primary" base={base} />
        </div>
      </div>
    </nav>
  );
}

export function Hero({
  eyebrow,
  heading,
  subheading,
  primaryCta,
  secondaryCta,
  image,
  align = "center",
  base,
}: BlockProps<"hero"> & BaseAware) {
  return (
    <header className={`pw-hero pw-hero--${align}`}>
      <div className="pw-container pw-hero__inner">
        <div className="pw-hero__content">
          {eyebrow ? <p className="pw-hero__eyebrow">{eyebrow}</p> : null}
          <h1 className="pw-hero__heading">{heading}</h1>
          {subheading ? <p className="pw-hero__subheading">{subheading}</p> : null}
          <div className="pw-hero__actions">
            <CtaLink link={primaryCta} variant="primary" base={base} />
            <CtaLink link={secondaryCta} variant="secondary" base={base} />
          </div>
        </div>
        {image ? (
          <div className="pw-hero__media">
            <img src={withBase(base, image)} alt={heading} />
          </div>
        ) : null}
      </div>
    </header>
  );
}

export function Features({
  heading,
  subheading,
  columns = 3,
  items = [],
}: BlockProps<"features">) {
  return (
    <section className="pw-section pw-features">
      <div className="pw-container">
        {heading ? <h2 className="pw-section__heading">{heading}</h2> : null}
        {subheading ? <p className="pw-section__subheading">{subheading}</p> : null}
