export * from "./schema";
export * from "./blocks";
export * from "./icons";
export * from "./base";
export * from "./post-components";
export * from "./bindings";
export { BlockRenderer, PageRenderer } from "./renderer";

import type {
  BlockProps,
  PostComponent,
  PostComponentType,
} from "./schema";

export interface PostComponentDefinition {
  label: string;
  description: string;
}

export const postComponentRegistry = {
  prose: {
    label: "Text",
    description: "Write and format the body of your post with Markdown.",
  },
  githubDiscussions: {
    label: "GitHub Discussions",
    description: "Add Giscus-powered comments and reactions backed by a GitHub repository.",
  },
} satisfies Record<PostComponentType, PostComponentDefinition>;

export interface GitHubDiscussionsConfigIssue {
  field: keyof BlockProps<"githubDiscussions">;
  message: string;
}

const REPO_PATTERN = /^[A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+$/;
const NODE_ID_PATTERN = /^[A-Za-z0-9_=-]{8,}$/;

/** Return actionable setup issues without preventing an author from saving an unfinished component. */
export function getGitHubDiscussionsConfigIssues(
  props: BlockProps<"githubDiscussions">,
): GitHubDiscussionsConfigIssue[] {
  const issues: GitHubDiscussionsConfigIssue[] = [];

  if (!props.repo.trim()) {
    issues.push({ field: "repo", message: "Choose the public repository that will store discussions." });
  } else if (!REPO_PATTERN.test(props.repo.trim())) {
    issues.push({ field: "repo", message: "Use the owner/repository format." });
  }

  if (!props.repoId.trim()) {
    issues.push({ field: "repoId", message: "Add the repository ID generated by giscus.app." });
  } else if (!NODE_ID_PATTERN.test(props.repoId.trim())) {
    issues.push({ field: "repoId", message: "Use the repository node ID generated by Giscus." });
  }

  if (!props.category.trim()) {
    issues.push({ field: "category", message: "Choose a GitHub Discussions category." });
  }

  if (!props.categoryId.trim()) {
    issues.push({ field: "categoryId", message: "Add the category ID generated by giscus.app." });
  } else if (!NODE_ID_PATTERN.test(props.categoryId.trim())) {
    issues.push({ field: "categoryId", message: "Use the category node ID generated by Giscus." });
  }

  if (props.mapping === "specific" && !props.term?.trim()) {
    issues.push({ field: "term", message: "Add the stable term used to find this post's discussion." });
  }

  if (props.mapping === "number" && !props.discussionNumber) {
    issues.push({ field: "discussionNumber", message: "Add the GitHub discussion number for this post." });
  }

  return issues;
}

export function isGitHubDiscussionsConfigured(
  props: BlockProps<"githubDiscussions">,
): boolean {
  return getGitHubDiscussionsConfigIssues(props).length === 0;
}

export function createPostComponent(
  type: "prose",
  options?: { id?: string; repo?: string },
): Extract<PostComponent, { type: "prose" }>;
export function createPostComponent(
  type: "githubDiscussions",
  options?: {
    id?: string;
    repo?: string;
    repoId?: string;
    category?: string;
    categoryId?: string;
  },
): Extract<PostComponent, { type: "githubDiscussions" }>;
export function createPostComponent(
  type: PostComponentType,
  options: {
    id?: string;
    repo?: string;
    repoId?: string;
    category?: string;
    categoryId?: string;
  } = {},
): PostComponent {
  const id = options.id ?? `${type}-${Date.now().toString(36)}`;
  if (type === "prose") {
    return {
      type,
      id,
      props: { markdown: "", html: "" },
    };
  }
  return {
    type,
    id,
    props: {
      repo: options.repo ?? "",
      repoId: options.repoId ?? "",
      category: options.category ?? "",
      categoryId: options.categoryId ?? "",
      mapping: "pathname",
      strict: true,
      reactionsEnabled: true,
      inputPosition: "top",
      theme: "preferred_color_scheme",
      lang: "en",
    },
  };
}

export function movePostComponent(
  components: readonly PostComponent[],
  id: string,
  toIndex: number,
): PostComponent[] {
  const fromIndex = components.findIndex((component) => component.id === id);
  if (fromIndex < 0 || toIndex < 0 || toIndex >= components.length || fromIndex === toIndex) {
    return [...components];
  }
  const next = [...components];
  const [component] = next.splice(fromIndex, 1);
  next.splice(toIndex, 0, component!);
  return next;
}

export function removePostComponent(
  components: readonly PostComponent[],
  id: string,
): PostComponent[] {
  return components.filter((component) => component.id !== id);
}

export function updatePostComponent<T extends PostComponentType>(
  components: readonly PostComponent[],
  id: string,
  props: Partial<BlockProps<T>>,
): PostComponent[] {
  return components.map((component) =>
    component.id === id
      ? ({ ...component, props: { ...component.props, ...props } } as PostComponent)
      : component,
  );
}

/** Migrate a locally-saved draft from the previous single-Markdown composer into the component list. */
export function applyLegacyMarkdownDraft(
  components: readonly PostComponent[],
  markdown: string,
  fallbackId = "prose-migrated-draft",
): PostComponent[] {
  const existingText = components.find((component) => component.type === "prose");
  if (existingText) {
    return updatePostComponent<"prose">(components, existingText.id, { markdown, html: "" });
  }
  return [
    {
      ...createPostComponent("prose", { id: fallbackId }),
      props: { markdown, html: "" },
    },
    ...components,
  ];
}

import * as React from "react";
import type { Block, SiteConfig } from "./schema";
import { blockRegistry } from "./blocks";
import {
  createSiteBindings,
  resolveBindings,
  resolveHtmlBindingString,
  type BindingValues,
} from "./bindings";

/** Render a single block by looking up its component in the registry. */
export function BlockRenderer({
  block,
  base,
  site,
  bindings = createSiteBindings(site),
}: {
  block: Block;
  base?: string;
  site?: SiteConfig;
  bindings?: BindingValues;
}) {
  const Component = blockRegistry[block.type] as React.FC<Record<string, unknown>>;
  if (!Component) {
    if (typeof console !== "undefined") {
      console.warn(`[pagewright] Unknown block type: ${(block as { type: string }).type}`);
    }
    return null;
  }
  const props = resolveBindings(block.props, bindings) as Record<string, unknown>;
  if (block.type === "prose") {
    props.html = resolveHtmlBindingString(block.props.html, bindings);
  }
  const resolvedSite = site ? resolveBindings(site, bindings) : undefined;
  return <Component {...props} base={base} site={resolvedSite} />;
}

/**
 * Render an ordered list of blocks (a page body). `base` is the site's base path
 * (`import.meta.env.BASE_URL` in Astro); it is threaded to every block as a prop so root-relative
 * image and link URLs resolve correctly on GitHub Pages project sites. Defaults to `/`. Kept
 * context-free so blocks remain renderable as React Server Components.
 */
export function PageRenderer({
  blocks,
  base,
  site,
}: {
  blocks: Block[];
  base?: string;
  site?: SiteConfig;
}) {
  const bindings = createSiteBindings(site);
  return (
    <>
      {blocks.map((block) => (
        <BlockRenderer
          key={block.id}
          block={block}
          base={base}
          site={site}
          bindings={bindings}
        />
      ))}
    </>
  );
}

import { z } from "zod";

/**
 * Pagewright content model.
 *
 * A page is an ordered list of typed blocks. This schema is the single source of
 * truth shared by the visual builder (Next.js) and the generated Astro sites, so
 * both render identical output and content is safe to migrate over time.
 */

export const linkSchema = z.object({
  label: z.string(),
  href: z.string(),
  icon: z.string().optional(),
});
export type Link = z.infer<typeof linkSchema>;

export const navbarBlockSchema = z.object({
  type: z.literal("navbar"),
  id: z.string(),
  props: z.object({
    brand: z.string(),
    logo: z.string().optional(),
    links: z.array(linkSchema).default([]),
    cta: linkSchema.optional(),
  }),
});

export const heroBlockSchema = z.object({
  type: z.literal("hero"),
  id: z.string(),
  props: z.object({
    eyebrow: z.string().optional(),
    heading: z.string(),
    subheading: z.string().optional(),
    primaryCta: linkSchema.optional(),
    secondaryCta: linkSchema.optional(),
    image: z.string().optional(),
    align: z.enum(["left", "center"]).default("center"),
  }),
});

export const featureItemSchema = z.object({
  /** Named icon from the shared block icon set (see `blockIcons`), e.g. "rocket". */
  icon: z.string().optional(),
  title: z.string(),
  body: z.string(),
});
export type FeatureItem = z.infer<typeof featureItemSchema>;

export const featuresBlockSchema = z.object({
  type: z.literal("features"),
  id: z.string(),
  props: z.object({
    heading: z.string().optional(),
    subheading: z.string().optional(),
    columns: z.union([z.literal(2), z.literal(3), z.literal(4)]).default(3),
    items: z.array(featureItemSchema).default([]),
  }),
});

export const ctaBlockSchema = z.object({
  type: z.literal("cta"),
  id: z.string(),
  props: z.object({
    heading: z.string(),
    body: z.string().optional(),
    primaryCta: linkSchema.optional(),
    secondaryCta: linkSchema.optional(),
  }),
});

export const proseBlockSchema = z.object({
  type: z.literal("prose"),
  id: z.string(),
  props: z.object({
    /** Markdown source (canonical for posts). Rendered to `html` at save time. */
    markdown: z.string().optional(),
    /** Rendered HTML the Astro template outputs directly (kept in sync with `markdown`). */
    html: z.string().default(""),
  }),
});

export const githubDiscussionsBlockSchema = z.object({
  type: z.literal("githubDiscussions"),
  id: z.string(),
  props: z.object({
    repo: z.string().default(""),
    repoId: z.string().default(""),
    category: z.string().default(""),
    categoryId: z.string().default(""),
    mapping: z
      .enum(["pathname", "url", "title", "og:title", "specific", "number"])
      .default("pathname"),
    term: z.string().optional(),
    discussionNumber: z.number().int().positive().optional(),
    strict: z.boolean().default(true),
    reactionsEnabled: z.boolean().default(true),
    inputPosition: z.enum(["top", "bottom"]).default("top"),
    theme: z.enum(["preferred_color_scheme", "light", "dark", "dark_dimmed"]).default("preferred_color_scheme"),
    lang: z.string().default("en"),
  }),
});

export const footerBlockSchema = z.object({
  type: z.literal("footer"),
  id: z.string(),
  props: z.object({
    brand: z.string().optional(),
    tagline: z.string().optional(),
    links: z.array(linkSchema).default([]),
    copyright: z.string().optional(),
  }),
});

export const galleryItemSchema = z.object({
  title: z.string(),
  description: z.string().optional(),
  image: z.string().optional(),
  href: z.string().optional(),
  tags: z.array(z.string()).default([]),
});
export type GalleryItem = z.infer<typeof galleryItemSchema>;

export const galleryBlockSchema = z.object({
  type: z.literal("gallery"),
  id: z.string(),
  props: z.object({
    heading: z.string().optional(),
    subheading: z.string().optional(),
    columns: z.union([z.literal(2), z.literal(3)]).default(3),
    items: z.array(galleryItemSchema).default([]),
  }),
});

export const blockSchema = z.discriminatedUnion("type", [
  navbarBlockSchema,
  heroBlockSchema,
  featuresBlockSchema,
  galleryBlockSchema,
  ctaBlockSchema,
  proseBlockSchema,
  githubDiscussionsBlockSchema,
  footerBlockSchema,
]);
export type Block = z.infer<typeof blockSchema>;
export type BlockType = Block["type"];
export type BlockProps<T extends BlockType> = Extract<Block, { type: T }>["props"];

export const postComponentSchema = z.discriminatedUnion("type", [
  proseBlockSchema,
  githubDiscussionsBlockSchema,
]);
export type PostComponent = z.infer<typeof postComponentSchema>;
export type PostComponentType = PostComponent["type"];
export const postComponentsSchema = z.array(postComponentSchema).superRefine((components, context) => {
  if (components.filter((component) => component.type === "githubDiscussions").length > 1) {
    context.addIssue({
      code: z.ZodIssueCode.custom,
      message: "A post can contain only one GitHub Discussions component.",
    });
  }
});

export const pageSchema = z.object({
  title: z.string(),
  description: z.string().optional(),
  slug: z.string().default("/"),
  draft: z.boolean().default(false),
  publishAt: z.string().datetime().optional(),
  blocks: z.array(blockSchema).default([]),
});
export type Page = z.infer<typeof pageSchema>;

/**
 * A blog post is a page document plus blog front-matter (date, excerpt, cover, tags, author).
 * Shared by the builder, the generated Astro blog template, and the scheduled-publish workflow.
 */
export const postSchema = pageSchema
  .extend({
    date: z.string(),
    excerpt: z.string().optional(),
    cover: z.string().optional(),
    tags: z.array(z.string()).default([]),
    author: z.string().optional(),
  })
  .superRefine((post, context) => {
    if (post.blocks.filter((block) => block.type === "githubDiscussions").length > 1) {
      context.addIssue({
        code: z.ZodIssueCode.custom,
        path: ["blocks"],
        message: "A post can contain only one GitHub Discussions component.",
      });
    }
  });
export type Post = z.infer<typeof postSchema>;

function isCanonicalHttpUrl(value: string): boolean {
  if (!/^https?:\/\//i.test(value)) return false;
  try {
    return ["http:", "https:"].includes(new URL(value).protocol);
  } catch {
    return false;
  }
}

function isExternalHref(value: string): boolean {
  if (!/^(?:https?:\/\/|mailto:|tel:)/i.test(value)) return false;
  try {
    const url = new URL(value);
    if (url.protocol === "http:" || url.protocol === "https:") {
      return isCanonicalHttpUrl(value);
    }
    return (
      (url.protocol === "mailto:" || url.protocol === "tel:") &&
      url.pathname.trim().length > 0
    );
  } catch {
    return false;
  }
}

const externalHrefSchema = z
  .string()
  .trim()
  .min(1)
  .refine(isExternalHref, "Enter a full http(s), mailto, or tel URL.");

const canonicalSiteUrlSchema = z
  .string()
  .trim()
  .refine((value) => !value || isCanonicalHttpUrl(value), "Enter a full http(s) URL.");

export const siteLinkSchema = linkSchema.extend({
  label: z.string().trim().min(1),
  href: externalHrefSchema,
}).passthrough();
export type SiteLink = z.infer<typeof siteLinkSchema>;

/**
 * Site-wide details and external links. `socials` is accepted as a legacy alias so sites generated
 * before global settings existed migrate to `links` the next time they are saved.
 */
export const siteConfigSchema = z
  .object({
    // Reads stay tolerant of legacy files; the settings write schema below applies stricter rules.
    name: z.string(),
    description: z.string().optional(),
    url: z.string().optional(),
    defaultTheme: z.enum(["light", "dark", "system"]).default("system"),
    links: z.array(siteLinkSchema).optional(),
    socials: z.array(linkSchema.passthrough()).optional(),
  })
  .passthrough()
  .transform(({ socials, links, ...config }) => ({
    ...config,
    links: links ?? socials ?? [],
  }));
export type SiteConfig = z.infer<typeof siteConfigSchema>;

const persistedSiteSettingsSchema = z
  .object({
    name: z.string().trim().min(1),
    description: z.string().optional(),
    url: canonicalSiteUrlSchema.optional(),
    defaultTheme: z.enum(["light", "dark", "system"]).default("system"),
    links: z.array(siteLinkSchema).default([]),
  })
  .passthrough();

/** Validate settings submitted by the app after applying legacy read migrations. */
export const siteSettingsSchema = siteConfigSchema.pipe(persistedSiteSettingsSchema);

/** Parse + apply defaults for an unknown page document (used when reading repo content). */
export function parsePage(input: unknown): Page {
  return pageSchema.parse(input);
}

/** Parse + apply defaults for an unknown blog post document. */
export function parsePost(input: unknown): Post {
  return postSchema.parse(input);
}

/** Parse + apply defaults and legacy migrations for an unknown site settings document. */
export function parseSiteConfig(input: unknown): SiteConfig {
  return siteConfigSchema.parse(input);
}

/* Pagewright block styles — self-contained, token-driven, framework-agnostic.
   Works identically in the Next.js builder preview and generated Astro sites.
   Dark mode responds to either a `.dark` class (next-themes) or [data-theme="dark"] (Astro). */

:root {
  --pw-bg: 0 0% 100%;
  --pw-fg: 240 10% 12%;
  --pw-muted: 240 5% 96%;
  --pw-muted-fg: 240 4% 44%;
  --pw-card: 0 0% 100%;
  --pw-border: 240 6% 90%;
  --pw-primary: 250 84% 60%;
  --pw-primary-fg: 0 0% 100%;
  --pw-focus-ring-inner: 0 0% 100%;
  --pw-focus-ring-outer: 240 10% 4%;
  --pw-focus-shadow:
    0 0 0 2px hsl(var(--pw-focus-ring-inner)),
    0 0 0 5px hsl(var(--pw-focus-ring-outer));
  --pw-accent: 33 95% 55%;
  --pw-radius: 12px;
  --pw-container: 1120px;
  --pw-font: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, Inter, sans-serif;
}

.dark,
[data-theme="dark"] {
  --pw-bg: 240 10% 7%;
  --pw-fg: 0 0% 98%;
  --pw-muted: 240 6% 14%;
  --pw-muted-fg: 240 5% 66%;
  --pw-card: 240 8% 11%;
  --pw-border: 240 5% 20%;
  --pw-primary: 250 90% 76%;
  --pw-primary-fg: 240 30% 8%;
  --pw-accent: 33 95% 60%;
}

.pw-root {
  background: hsl(var(--pw-bg));
  color: hsl(var(--pw-fg));
  font-family: var(--pw-font);
  line-height: 1.55;
  -webkit-font-smoothing: antialiased;
}

.pw-container {
  width: 100%;
  max-width: var(--pw-container);
  margin-inline: auto;
  padding-inline: 24px;
}

.pw-section {
  padding-block: 72px;
}

.pw-section__heading {
  font-size: clamp(1.6rem, 3vw, 2.25rem);
  font-weight: 700;
  letter-spacing: -0.02em;
  text-align: center;
  margin: 0 0 8px;
}

.pw-section__subheading {
  color: hsl(var(--pw-muted-fg));
  text-align: center;
  max-width: 640px;
  margin: 0 auto 40px;
}

/* Buttons */
.pw-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 11px 20px;
  border-radius: calc(var(--pw-radius) - 4px);
  font-weight: 600;
  font-size: 0.95rem;
  text-decoration: none;
  border: 1px solid transparent;
  transition: transform 0.06s ease, opacity 0.15s ease, background 0.15s ease;
}
.pw-btn:active { transform: translateY(1px); }
.pw-btn:focus-visible {
  outline: 2px solid transparent;
  outline-offset: 2px;
  box-shadow: var(--pw-focus-shadow) !important;
}
.pw-btn--primary {
  background: hsl(var(--pw-primary));
  color: hsl(var(--pw-primary-fg));
}
.pw-btn--primary:hover { opacity: 0.92; }
.pw-btn--secondary {
  background: transparent;
  color: hsl(var(--pw-fg));
  border-color: hsl(var(--pw-border));
}
.pw-btn--secondary:hover { background: hsl(var(--pw-muted)); }

/* Navbar */
.pw-navbar {
  border-bottom: 1px solid hsl(var(--pw-border));
  background: hsl(var(--pw-bg) / 0.8);
  backdrop-filter: blur(8px);
  position: sticky;
  top: 0;
  z-index: 20;
}
.pw-navbar__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
}
.pw-navbar__brand {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-weight: 700;
  color: hsl(var(--pw-fg));
  text-decoration: none;
  font-size: 1.05rem;
}
.pw-navbar__logo { height: 28px; width: auto; }
.pw-navbar__links { display: flex; align-items: center; gap: 20px; }
.pw-navbar__link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: hsl(var(--pw-muted-fg));
  text-decoration: none;
  font-size: 0.95rem;
  font-weight: 500;
}
.pw-navbar__link:hover { color: hsl(var(--pw-fg)); }

/* Hero */
.pw-hero { padding-block: 96px; }
.pw-hero__inner { display: grid; gap: 40px; align-items: center; }
.pw-hero--center .pw-hero__inner { text-align: center; justify-items: center; }
.pw-hero--left .pw-hero__content { max-width: 620px; }
.pw-hero__eyebrow {
  display: inline-block;
  color: hsl(var(--pw-primary));
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  font-size: 0.8rem;
  margin: 0 0 12px;
}
.pw-hero__heading {
  font-size: clamp(2.25rem, 5vw, 3.5rem);
  font-weight: 800;
  letter-spacing: -0.03em;
  line-height: 1.05;
  margin: 0 0 16px;
}
.pw-hero__subheading {
  font-size: clamp(1.05rem, 2vw, 1.25rem);
  color: hsl(var(--pw-muted-fg));
  max-width: 640px;
  margin: 0 0 28px;
}
.pw-hero--center .pw-hero__subheading { margin-inline: auto; }
.pw-hero__actions { display: flex; gap: 12px; flex-wrap: wrap; }
.pw-hero--center .pw-hero__actions { justify-content: center; }
.pw-hero__media img {
  width: 100%;
  height: auto;
  border-radius: var(--pw-radius);
  border: 1px solid hsl(var(--pw-border));
}

/* Features */
.pw-features__grid { display: grid; gap: 24px; }
.pw-cols-2 { grid-template-columns: repeat(2, minmax(0, 1fr)); }
.pw-cols-3 { grid-template-columns: repeat(3, minmax(0, 1fr)); }
.pw-cols-4 { grid-template-columns: repeat(4, minmax(0, 1fr)); }
.pw-feature {
  background: hsl(var(--pw-card));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  padding: 24px;
}
.pw-feature__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 46px;
  height: 46px;
  margin-bottom: 14px;
  border-radius: 12px;
  color: hsl(var(--pw-primary));
  background: hsl(var(--pw-primary) / 0.1);
}
.pw-feature__icon svg { display: block; }
.pw-feature__title { font-size: 1.1rem; font-weight: 700; margin: 0 0 6px; }
.pw-feature__body { color: hsl(var(--pw-muted-fg)); margin: 0; font-size: 0.95rem; }

/* CTA */
.pw-cta__inner {
  background: linear-gradient(135deg, hsl(var(--pw-primary)), hsl(var(--pw-accent)));
  color: #fff;
  border-radius: calc(var(--pw-radius) + 4px);
  padding: 56px 32px;
  text-align: center;
}
.pw-cta__heading { font-size: clamp(1.6rem, 3vw, 2.25rem); font-weight: 800; margin: 0 0 12px; }
.pw-cta__body { opacity: 0.95; max-width: 560px; margin: 0 auto 24px; }
.pw-cta__actions { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.pw-cta .pw-btn--secondary { color: #fff; border-color: rgba(255, 255, 255, 0.5); }
.pw-cta .pw-btn--primary { background: #fff; color: hsl(240 30% 12%); }

/* Prose — rich typography for markdown-rendered post/page content. Tailwind's
   Preflight resets headings/lists to unstyled, so every element is styled
   explicitly here. Token-driven so it themes in light/dark and renders
   identically in the composer preview and on deployed Astro sites. */
.pw-prose {
  max-width: 720px;
  color: hsl(var(--pw-fg));
  font-size: 1.0625rem;
  line-height: 1.75;
}
.pw-prose > :first-child { margin-top: 0; }
.pw-prose > :last-child { margin-bottom: 0; }
.pw-prose h1,
.pw-prose h2,
.pw-prose h3,
.pw-prose h4 {
  letter-spacing: -0.02em;
  font-weight: 700;
  line-height: 1.25;
  color: hsl(var(--pw-fg));
}
.pw-prose h1 { font-size: 2rem; font-weight: 800; margin: 2rem 0 1rem; }
.pw-prose h2 { font-size: 1.5rem; margin: 1.75rem 0 0.75rem; }
.pw-prose h3 { font-size: 1.25rem; margin: 1.5rem 0 0.5rem; }
.pw-prose h4 { font-size: 1.0625rem; margin: 1.25rem 0 0.5rem; }
.pw-prose p { margin: 0 0 1rem; }
.pw-prose a {
  color: hsl(var(--pw-primary));
  text-decoration: underline;
  text-underline-offset: 2px;
}
.pw-prose strong { font-weight: 700; color: hsl(var(--pw-fg)); }
.pw-prose em { font-style: italic; }
.pw-prose ul,
.pw-prose ol { margin: 0 0 1rem; padding-left: 1.5rem; }
.pw-prose ul { list-style: disc; }
.pw-prose ol { list-style: decimal; }
.pw-prose li { margin: 0.35rem 0; }
.pw-prose li > ul,
.pw-prose li > ol { margin: 0.35rem 0; }
.pw-prose blockquote {
  margin: 0 0 1rem;
  padding: 0.25rem 0 0.25rem 1rem;
  border-left: 3px solid hsl(var(--pw-border));
  color: hsl(var(--pw-muted-fg));
  font-style: italic;
}
.pw-prose code {
  font-family: ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace;
  font-size: 0.9em;
  background: hsl(var(--pw-muted));
  border: 1px solid hsl(var(--pw-border));
  border-radius: 6px;
  padding: 0.1em 0.35em;
}
.pw-prose pre {
  margin: 0 0 1rem;
  padding: 1rem 1.15rem;
  background: hsl(var(--pw-muted));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  overflow-x: auto;
  line-height: 1.6;
}
.pw-prose pre code {
  background: none;
  border: 0;
  padding: 0;
  font-size: 0.875rem;
}
.pw-prose hr {
  margin: 2rem 0;
  border: 0;
  border-top: 1px solid hsl(var(--pw-border));
}
.pw-prose img { max-width: 100%; height: auto; border-radius: var(--pw-radius); }
.pw-prose table {
  width: 100%;
  margin: 0 0 1rem;
  border-collapse: collapse;
  font-size: 0.95em;
}
.pw-prose th,
.pw-prose td {
  border: 1px solid hsl(var(--pw-border));
  padding: 0.5rem 0.75rem;
  text-align: left;
}
.pw-prose th { background: hsl(var(--pw-muted)); font-weight: 700; }

/* GitHub Discussions */
.pw-discussion {
  padding-block: 24px 72px;
}
.pw-discussion__inner {
  max-width: 768px;
}
.pw-discussion__header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 24px;
  margin-bottom: 24px;
}
.pw-discussion__heading {
  margin: 0 0 6px;
  color: hsl(var(--pw-fg));
  font-size: 1.5rem;
  font-weight: 750;
  letter-spacing: -0.02em;
}
.pw-discussion__intro {
  margin: 0;
  max-width: 56ch;
  color: hsl(var(--pw-muted-fg));
  font-size: 0.925rem;
}
.pw-discussion__github {
  flex: none;
  display: inline-flex;
  align-items: center;
  min-height: 38px;
  padding: 8px 13px;
  border: 1px solid hsl(var(--pw-border));
  border-radius: calc(var(--pw-radius) - 4px);
  background: hsl(var(--pw-card));
  color: hsl(var(--pw-fg));
  font-size: 0.875rem;
  font-weight: 650;
  line-height: 1;
  text-decoration: none;
}
.pw-discussion__github:hover {
  border-color: hsl(var(--pw-primary) / 0.55);
  background: hsl(var(--pw-muted));
}
.pw-discussion__github:focus-visible,
.pw-discussion__setup a:focus-visible {
  outline: 3px solid hsl(var(--pw-primary) / 0.35);
  outline-offset: 2px;
}
.pw-discussion__setup {
  padding: 20px;
  border: 1px dashed hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  background: hsl(var(--pw-muted) / 0.45);
  color: hsl(var(--pw-fg));
}
.pw-discussion__setup p {
  margin: 5px 0 10px;
  color: hsl(var(--pw-muted-fg));
  font-size: 0.925rem;
}
.pw-discussion__setup a {
  color: hsl(var(--pw-primary));
  font-size: 0.9rem;
  font-weight: 650;
}
.pw-discussion__embed {
  min-height: 180px;
}
.pw-discussion__loading {
  display: grid;
  gap: 12px;
  padding: 18px 0;
  color: hsl(var(--pw-muted-fg));
  font-size: 0.825rem;
}
.pw-discussion__loading i {
  display: block;
  height: 14px;
  border-radius: 7px;
  background: hsl(var(--pw-muted));
  animation: pw-discussion-pulse 1.5s ease-in-out infinite alternate;
}
.pw-discussion__loading i:nth-of-type(2) { width: 84%; }
.pw-discussion__loading i:nth-of-type(3) { width: 62%; }
.pw-discussion__embed:has(.giscus-frame) .pw-discussion__loading {
  display: none;
}
.pw-discussion__embed .giscus,
.pw-discussion__embed .giscus-frame {
  width: 100%;
}
@keyframes pw-discussion-pulse {
  from { opacity: 0.45; }
  to { opacity: 1; }
}
@media (prefers-reduced-motion: reduce) {
  .pw-discussion__loading i { animation: none; }
}

/* Footer */
.pw-footer {
  border-top: 1px solid hsl(var(--pw-border));
  padding-block: 40px 24px;
  margin-top: 40px;
}
.pw-footer__inner {
  display: flex;
  justify-content: space-between;
  gap: 24px;
  flex-wrap: wrap;
}
.pw-footer__tagline { color: hsl(var(--pw-muted-fg)); margin: 6px 0 0; font-size: 0.9rem; }
.pw-footer__links { display: flex; gap: 20px; flex-wrap: wrap; }
.pw-footer__link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: hsl(var(--pw-muted-fg));
  text-decoration: none;
  font-size: 0.9rem;
}
.pw-footer__link:hover { color: hsl(var(--pw-fg)); }
.pw-footer__copyright { color: hsl(var(--pw-muted-fg)); font-size: 0.85rem; margin-top: 24px; }
.pw-linkicon { display: inline-flex; align-items: center; justify-content: center; flex: none; }

/* Shared tags */
.pw-tag {
  display: inline-block;
  font-size: 0.72rem;
  font-weight: 600;
  padding: 2px 9px;
  border-radius: 999px;
  color: hsl(var(--pw-muted-fg));
  background: hsl(var(--pw-muted));
  border: 1px solid hsl(var(--pw-border));
}

/* Gallery (portfolio) */
.pw-gallery__grid { display: grid; gap: 24px; }
.pw-gallery__item {
  display: block;
  background: hsl(var(--pw-card));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  overflow: hidden;
  text-decoration: none;
  color: inherit;
  transition: transform 0.15s ease, border-color 0.15s ease;
}
.pw-gallery__item--link:hover { transform: translateY(-3px); border-color: hsl(var(--pw-primary)); }
.pw-gallery__media { aspect-ratio: 16 / 10; overflow: hidden; background: hsl(var(--pw-muted)); }
.pw-gallery__media img { width: 100%; height: 100%; object-fit: cover; display: block; }
.pw-gallery__body { padding: 18px 20px 22px; }
.pw-gallery__title { font-size: 1.1rem; font-weight: 700; margin: 0 0 6px; }
.pw-gallery__desc { color: hsl(var(--pw-muted-fg)); margin: 0 0 12px; font-size: 0.95rem; }
.pw-gallery__tags { display: flex; gap: 8px; flex-wrap: wrap; }

/* Blog post list */
.pw-postlist__grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 24px;
}
.pw-postlist__empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: 6px;
  max-width: 460px;
  margin: 8px auto 0;
  padding: 44px 28px;
  border: 1px dashed hsl(var(--pw-border));
  border-radius: calc(var(--pw-radius) + 2px);
  background: hsl(var(--pw-muted) / 0.4);
}
.pw-postlist__emptyicon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 52px;
  height: 52px;
  margin-bottom: 8px;
  border-radius: 14px;
  color: hsl(var(--pw-primary));
  background: hsl(var(--pw-primary) / 0.1);
}
.pw-postlist__emptytitle { font-size: 1.15rem; font-weight: 700; margin: 0; letter-spacing: -0.01em; }
.pw-postlist__emptybody { color: hsl(var(--pw-muted-fg)); margin: 0; font-size: 0.95rem; }

/* Coming-soon / scheduled posts */
.pw-upcoming { margin-top: 44px; }
.pw-upcoming__heading {
  display: flex;
  align-items: center;
  gap: 9px;
  justify-content: center;
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: hsl(var(--pw-muted-fg));
  margin: 0 0 22px;
}
.pw-upcoming__dot {
  width: 8px;
  height: 8px;
  border-radius: 999px;
  background: hsl(var(--pw-primary));
  box-shadow: 0 0 0 4px hsl(var(--pw-primary) / 0.16);
}
.pw-postcard--soon {
  cursor: default;
  border-style: dashed;
  background: hsl(var(--pw-muted) / 0.35);
}
.pw-postcard--soon:hover { transform: none; border-color: hsl(var(--pw-border)); }
.pw-postcard--soon .pw-postcard__title,
.pw-postcard--soon .pw-postcard__excerpt { opacity: 0.85; }
.pw-postcard__badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.03em;
  padding: 3px 10px;
  border-radius: 999px;
  color: hsl(var(--pw-primary));
  background: hsl(var(--pw-primary) / 0.1);
  border: 1px solid hsl(var(--pw-primary) / 0.28);
  margin-bottom: 10px;
}
.pw-postcard__badgedot {
  width: 6px;
  height: 6px;
  border-radius: 999px;
  background: hsl(var(--pw-primary));
  animation: pw-soonpulse 1.8s ease-in-out infinite;
}
@keyframes pw-soonpulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.35; transform: scale(0.8); }
}
@media (prefers-reduced-motion: reduce) {
  .pw-postcard__badgedot { animation: none; }
}
.pw-postcard {
  display: flex;
  flex-direction: column;
  background: hsl(var(--pw-card));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  overflow: hidden;
  text-decoration: none;
  color: inherit;
  transition: transform 0.15s ease, border-color 0.15s ease;
}
.pw-postcard:hover { transform: translateY(-3px); border-color: hsl(var(--pw-primary)); }
.pw-postcard__media { aspect-ratio: 16 / 9; overflow: hidden; background: hsl(var(--pw-muted)); }
.pw-postcard__media img { width: 100%; height: 100%; object-fit: cover; display: block; }
.pw-postcard__body { padding: 18px 20px 22px; }
.pw-postcard__date { font-size: 0.8rem; color: hsl(var(--pw-muted-fg)); }
.pw-postcard__title { font-size: 1.15rem; font-weight: 700; margin: 6px 0 8px; letter-spacing: -0.01em; }
.pw-postcard__excerpt { color: hsl(var(--pw-muted-fg)); margin: 0 0 12px; font-size: 0.95rem; }
.pw-postcard__tags { display: flex; gap: 8px; flex-wrap: wrap; }

/* Single post header */
.pw-posthead { padding: 56px 0 24px; border-bottom: 1px solid hsl(var(--pw-border)); }
.pw-posthead__inner { max-width: 720px; }
.pw-posthead__meta { color: hsl(var(--pw-muted-fg)); font-size: 0.9rem; margin-bottom: 10px; }
.pw-posthead__author { margin-left: 4px; }
.pw-posthead__title { font-size: clamp(1.8rem, 4vw, 2.6rem); font-weight: 800; letter-spacing: -0.02em; margin: 0 0 14px; }
.pw-posthead__tags { display: flex; gap: 8px; flex-wrap: wrap; }

@media (max-width: 860px) {
  .pw-cols-3, .pw-cols-4 { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .pw-postlist__grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .pw-navbar__links .pw-navbar__link { display: none; }
}
@media (max-width: 560px) {
  .pw-cols-2, .pw-cols-3, .pw-cols-4 { grid-template-columns: 1fr; }
  .pw-postlist__grid { grid-template-columns: 1fr; }
  .pw-discussion__header { flex-direction: column; }
  .pw-discussion__github { width: 100%; justify-content: center; }
}

{
  "name": "@pagewright/site-kit",
  "version": "0.1.1",
  "type": "module",
  "description": "Versioned Astro rendering kit for Pagewright sites (theme script, schema, migrations).",
  "exports": {
    ".": "./src/index.ts"
  },
  "scripts": {
    "build": "tsc --noEmit",
    "typecheck": "tsc --noEmit"
  },
  "dependencies": {
    "@pagewright/blocks": "file:../pagewright-blocks"
  },
  "peerDependencies": {
    "astro": ">=5.0.0"
  },
  "devDependencies": {
    "typescript": "^5.7.2"
  }
}

export * from "@pagewright/blocks/schema";

/** Version of the kit a generated site is pinned to. Drives the self-update PR flow. */
export const KIT_VERSION = "0.1.1";

/**
 * Render-blocking inline script that applies the persisted or system theme before first
 * paint (prevents a flash of the wrong theme). Sets both a `.dark` class (matches next-themes)
 * and `data-theme` so block CSS resolves identically in the builder and on the live site.
 */
export function createThemeInitScript(
  defaultTheme: "light" | "dark" | "system" = "system",
): string {
  return `(function(){try{var e=localStorage.getItem("pw-theme");var f=${JSON.stringify(defaultTheme)};var t=e==="light"||e==="dark"||e==="system"?e:f;var m=window.matchMedia&&window.matchMedia("(prefers-color-scheme: dark)").matches;var d=t==="dark"||(t==="system"&&m);var r=document.documentElement;r.classList.toggle("dark",!!d);r.setAttribute("data-theme",d?"dark":"light");}catch(_){}})();`;
}

export const themeInitScript = createThemeInitScript();
